import{c as t,Q as a,j as r,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"How do I triage a discrepancy?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/triage-discrepancy.md","filePath":"guide/recipes/admin/triage-discrepancy.md","lastUpdated":1778912818000}'),o={name:"guide/recipes/admin/triage-discrepancy.md"};function i(n,e,l,c,d,g){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-triage-a-discrepancy" tabindex="-1">How do I triage a discrepancy? <a class="header-anchor" href="#how-do-i-triage-a-discrepancy" aria-label="Permalink to &quot;How do I triage a discrepancy?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong> for purge/discard. <strong>Compliance Admin</strong> and <strong>Reader</strong> can view but not act.</p></div><p>The Discrepancies inbox lists tenant-level dangles. For each one you can purge (delete the dangle), discard (snooze until the next scan), or leave open for investigation.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>System → Discrepancies</strong>.</li><li>Filter by <strong>kind</strong> (ghost / orphan) or <strong>instance</strong> to narrow the inbox.</li><li>Click a row to see the dangle&#39;s details — IDs, last-seen time, the resource it points to.</li><li>Pick an action: <ul><li><strong>Purge</strong> — delete the dangle in its store (Postgres for ghosts, Mongo for orphans).</li><li><strong>Discard</strong> — dismiss from the current inbox. The next audit cycle will re-surface it if still present.</li><li><strong>Investigate</strong> — leave it open and look into the underlying cause.</li></ul></li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li><strong>Purge</strong> moves the record to status <strong>Resolved</strong> with your operator ID and a timestamp.</li><li><strong>Discard</strong> moves it to <strong>Discarded</strong> — note that the next scan can flip it back to <strong>Open</strong> if the dangle reappears (discard is &quot;snooze until next audit&quot;).</li></ul><div class="warning custom-block"><p class="custom-block-title">Discard isn&#39;t permanent</p><p>The ideal system has zero dangles. Discard is for &quot;this one is acceptable right now, check next cycle&quot; — not &quot;ignore forever&quot;.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./run-discrepancy-audit">How do I trigger a discrepancy audit?</a></li></ul>',10)])])}const h=t(o,[["render",i]]);export{u as __pageData,h as default};
